The standard implementation from the quill-delta npm package:

```typescript
static compose(
  a: AttributeMap | undefined,
  b: AttributeMap | undefined,
  keepNull: boolean,
): AttributeMap | undefined {
  if (typeof a !== 'object') a = {};
  if (typeof b !== 'object') b = {};
  let attributes = Object.keys(b).reduce<AttributeMap>((copy, key) => {
    if (b[key] !== null || keepNull) {
      copy[key] = b[key];
    }
    return copy;
  }, {});
  if (Object.keys(attributes).length === 0) {
    return undefined;
  }
  return Object.keys(a).reduce<AttributeMap>((copy, key) => {
    if (copy[key] === undefined) {
      copy[key] = a[key];
    }
    return copy;
  }, attributes);
}
```

